const _CsvWriter = struct { buf: std.ArrayList(u8) };
fn _csv_writer_init() _CsvWriter { return .{ .buf = .{} }; }
fn _csv_write_row(w: *_CsvWriter, row: std.ArrayList([]const u8)) void {
    const _pa = std.heap.page_allocator;
